namespace sv_297276499a324349a90a4e3b959f1b43.Models;

public class WizardState
{
    // Step 1 — Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 — Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3 — References
    public List<ReferenceContact> References { get; set; } = [];

    /// <summary>
    /// Tracks which steps have been completed (1-based).
    /// </summary>
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_297276499a324349a90a4e3b959f1b43.Models;

namespace sv_297276499a324349a90a4e3b959f1b43.Services;

/// <summary>
/// Singleton in-memory store for wizard data, keyed by a cookie-based session ID.
/// Each applicant gets an independent <see cref="WizardState"/> instance.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
        => _states.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId)
        => _states.TryRemove(sessionId, out _);
}

@inherits LayoutComponentBase
@inject Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

@{
    var steps = new (string Label, string Href)[]
    {
        ("Personal Info", "/apply/personal-info"),
        ("Experience",    "/apply/experience"),
        ("References",    "/apply/references"),
        ("Review",        "/apply/review"),
    };

    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    int currentStep = Array.FindIndex(steps, s =>
        currentPath.Equals(s.Href, StringComparison.OrdinalIgnoreCase)) + 1;
    if (currentStep == 0) currentStep = 1;

    var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    var state = string.IsNullOrEmpty(sessionId) ? null : Store.GetOrCreate(sessionId);
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <span class="me-auto fw-semibold">Step @currentStep of @steps.Length</span>
        </div>

        <nav class="px-4 pt-3 pb-2">
            <div class="d-flex gap-2 align-items-center">
                @for (int i = 0; i < steps.Length; i++)
                {
                    var step = steps[i];
                    int stepNum = i + 1;
                    bool isActive = stepNum == currentStep;
                    bool isCompleted = state?.CompletedSteps.Contains(stepNum) == true;

                    string badgeCss = isActive ? "bg-primary"
                        : isCompleted ? "bg-success"
                        : "bg-secondary";

                    <a href="@step.Href"
                       class="text-decoration-none d-flex align-items-center gap-1 @(isActive ? "fw-bold" : "text-muted")">
                        <span class="badge rounded-pill @badgeCss">@stepNum</span>
                        <span class="d-none d-md-inline">@step.Label</span>
                    </a>

                    if (stepNum < steps.Length)
                    {
                        <hr class="flex-grow-1 mx-1" />
                    }
                }
            </div>
        </nav>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@page "/apply/personal-info"
@layout Layout.WizardLayout
@rendermode InteractiveServer
@inject Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Personal Info — Apply</PageTitle>

<h1>Personal Information</h1>

<div class="mb-3" style="max-width:500px">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="name" @bind:event="oninput" />
</div>

<div class="mb-3" style="max-width:500px">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="email" @bind:event="oninput" />
</div>

<button class="btn btn-primary" @onclick="Next" disabled="@(!IsValid)">Next →</button>

@code {
    private string? sessionId;
    private string name = string.Empty;
    private string email = string.Empty;

    private bool IsValid => !string.IsNullOrWhiteSpace(name)
                         && !string.IsNullOrWhiteSpace(email);

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (string.IsNullOrEmpty(sessionId)) return;

        var state = Store.GetOrCreate(sessionId);
        name = state.Name;
        email = state.Email;
    }

    private void Next()
    {
        if (string.IsNullOrEmpty(sessionId) || !IsValid) return;

        var state = Store.GetOrCreate(sessionId);
        state.Name = name;
        state.Email = email;
        state.CompletedSteps.Add(1);

        Nav.NavigateTo("/apply/experience");
    }
}

