@layout Layout.WizardLayout
@rendermode InteractiveServer
@inject Services.WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Review — Apply</PageTitle>

<h1>Review Your Application</h1>

@if (state is null)
{
    <p>No application data found. <a href="/apply/personal-info">Start over</a>.</p>
}
else
{
    <div style="max-width:600px">
        <h4>Personal Information</h4>
        <dl class="row">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@state.Name</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@state.Email</dd>
        </dl>

        <h4>Work Experience</h4>
        @if (state.Jobs.Count == 0)
        {
            <p class="text-muted">No jobs added.</p>
        }
        else
        {
            <ul class="list-group mb-3">
                @foreach (var job in state.Jobs)
                {
                    <li class="list-group-item">
                        <strong>@job.Title</strong> at @job.Company (@job.Years)
                    </li>
                }
            </ul>
        }

        <h4>References</h4>
        @if (state.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            <ul class="list-group mb-3">
                @foreach (var r in state.References)
                {
                    <li class="list-group-item">
                        <strong>@r.Name</strong> — @r.Relationship (@r.Email)
                    </li>
                }
            </ul>
        }

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/apply/references")'>← Back</button>
            <button class="btn btn-success" @onclick="Submit">Submit Application</button>
        </div>

        @if (submitted)
        {
            <div class="alert alert-success mt-3">Application submitted! 🎉</div>
        }
    </div>
}

@code {
    private string? sessionId;
    private Models.WizardState? state;
    private bool submitted;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"];
        if (string.IsNullOrEmpty(sessionId)) return;

        state = Store.GetOrCreate(sessionId);
    }

    private void Submit()
    {
        submitted = true;
        // In a real app you'd persist to a database and clear the store:
